import{_ as t,o as a,c as o,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Second Install Deduplication and Methodology","description":"","frontmatter":{"title":"Second Install Deduplication and Methodology","slug":"second-install-deduplication-methodology"},"headers":[],"relativePath":"marketer-hub/second-install-deduplication-methodology.md","filePath":"marketer-hub/second-install-deduplication-methodology.md"}'),n={name:"marketer-hub/second-install-deduplication-methodology.md"};function s(r,e,l,d,p,c){return a(),o("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>iOS 14.5 brought big changes to the mobile attribution ecosystem. One big change is that IDFA is not accessible on app install, but it can be accessed later if the user consents to <a href="https://developer.apple.com/app-store/user-privacy-and-data-use/" target="_blank" rel="noreferrer">Apple&#39;s AppTrackingTransparency framework</a>. Currently, if the user installed the mobile app via a paid ad, then Branch will publish a second install event for that user that is attributed to the ad (assuming the user allowed tracking on both source and destination apps). This means that for a subset of users, there are technically two install events. In order to ensure you see accurate counts for installs, Branch has now provided functionality to &quot;remove&quot; the first unattributed install.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li><p>User sees a paid ad in a publisher app (ex. Facebook/Instagram).</p></li><li><p>User clicks the ad and gets routed to App Store to download the advertiser app.</p></li><li><p>User installs and opens the advertiser app.</p></li><li><p>An unattributed (<em>first</em>) install is reported in Branch&#39;s attribution system.</p></li></ol><p>.png)</p><ol start="5"><li><p>After some time or after an event, the advertiser app prompts the user for tracking through Apple&#39;s AppTrackingTransparency framework.</p></li><li><p>If the user opts into tracking in the advertiser app <strong>and</strong> the user has opted into tracking in the publisher app where they originally saw the paid ad, then Branch will report a <em>second</em> install.</p></li><li><p>Once the deduplication is enabled, Branch will automatically &quot;remove&quot; the first unattributed install. The second install will take the timestamp of the first install.</p></li></ol><p>.png)</p><h2 id="deduplicate-installs" tabindex="-1">Deduplicate installs <a class="header-anchor" href="#deduplicate-installs" aria-label="Permalink to &quot;Deduplicate installs&quot;">​</a></h2><p>Please note that enabling via the Branch Dashboard will only affect the views/reports of that user.</p><ol><li><p>Log in to the Branch Dashboard and navigate to the <strong>User</strong> <a href="https://dashboard.branch.io/account-settings/user" target="_blank" rel="noreferrer">view</a> in <strong>Account Settings</strong>.</p></li><li><p>Scroll down and toggle the <strong>Advanced calculation for organic analytics</strong> checkbox under the <strong>Analytic Settings</strong> section.</p></li></ol><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>If you want to deduplicate installs for all users and views, visit our <a href="./deduplicate-second-installs-with-apis.html">developer documentation</a> for more information on how to deduplicate installs using Branch APIs.</p></div>',11)])])}const g=t(n,[["render",s]]);export{u as __pageData,g as default};
